// Solution
import sys
from collections import defaultdict

class Solution:
    def find_first_duplicate(self, arr):
        freq = {}
        for num in arr:
            freq[num] = freq.get(num, 0) + 1
        for num in arr:
            if freq[num] > 1:
                return num
        return -1

if __name__ == '__main__':
    solution = Solution()
    n = int(input())
    arr = list(map(int, input().split()))
    result = solution.find_first_duplicate(arr)
    print(result)

